def calculate_cpa_ovulation_suppression(dose_mg):
    if dose_mg == 0.5:
        return 0.6  # 3 out of 5 = 60%
    elif dose_mg == 1.0:
        return 1.0  # 5 out of 5 = 100%
    else:
        return 0.0  # No data for other doses

# Example usage:
suppression_rate = calculate_cpa_ovulation_suppression(1.0)
print(f"Ovulation suppression rate at 1 mg/day: {suppression_rate * 100}%")
